// Compiles src/client/index.ts → src/client-bundle.ts (auto-generated, do not edit directly)
import { build } from 'esbuild';
import { writeFileSync } from 'fs';

const result = await build({
  entryPoints: ['src/client/index.ts'],
  bundle: true,
  minify: true,
  write: false,
  format: 'iife',
  target: ['es2022'],
  tsconfig: 'src/client/tsconfig.json',
});

const js = result.outputFiles[0].text;
writeFileSync(
  'src/client-bundle.ts',
  `// Auto-generated by build-client.mjs — edit src/client/index.ts instead\nexport const CLIENT_SCRIPT = ${JSON.stringify(js)};\n`,
);

console.log('[dashboard] client bundle generated (' + js.length + ' bytes)');
